import { z } from 'zod';

// Environment variables validation schema
const envSchema = z.object({
  VITE_API_BASE_URL: z.string(), // Allow relative URLs for nginx proxy
  VITE_WS_BASE_URL: z.string(),  // Allow empty string for relative WebSocket
});

// Parse and validate environment variables
const parseEnvVars = () => {
  // If VITE_API_URL is empty or not set, use relative URLs (for nginx proxy)
  const apiUrl = import.meta.env.VITE_API_URL;
  const wsUrl = import.meta.env.VITE_WS_URL;

  // Use relative URLs when variables are empty (for nginx proxy)
  if (!apiUrl || apiUrl === '') {
    return {
      VITE_API_BASE_URL: '/api',
      VITE_WS_BASE_URL: '',
    };
  }

  const env = {
    VITE_API_BASE_URL: apiUrl ? `${apiUrl}/api` : import.meta.env.VITE_API_BASE_URL || '/api',
    VITE_WS_BASE_URL: wsUrl || import.meta.env.VITE_WS_BASE_URL || '',
  };

  try {
    return envSchema.parse(env);
  } catch (error) {
    console.error('Environment validation failed:', error);
    // Fallback to relative URLs for nginx proxy
    return {
      VITE_API_BASE_URL: '/api',
      VITE_WS_BASE_URL: '',
    };
  }
};

const env = parseEnvVars();

// API Configuration
export const API_CONFIG = {
  // Base URLs
  BASE_URL: env.VITE_API_BASE_URL,
  WS_BASE_URL: env.VITE_WS_BASE_URL,

  // Timeout settings
  TIMEOUT: {
    DEFAULT: 10000, // 10 seconds for normal requests
    UPLOAD: 30000,  // 30 seconds for file uploads
  },

  // Retry settings
  RETRY: {
    ATTEMPTS: 3,
    DELAY: 1000, // Base delay in milliseconds for exponential backoff
  },

  // Endpoints
  ENDPOINTS: {
    // Health check
    HEALTH: '/health',

    // Authentication
    AUTH: {
      LOGIN: '/auth/login',
      REFRESH: '/auth/refresh',
      LOGOUT: '/auth/logout',
      FORGOT_PASSWORD: '/auth/forgot',
      RESET_PASSWORD: '/auth/reset',
    },

    // Core resources (following backend API pattern)
    SALONS: '/salons',
    USERS: '/users',
    CLIENTS: '/clients',
    SERVICES: '/services',
    SPECIALTIES: '/specialties',
    APPOINTMENTS: '/appointments',
    REQUESTS: '/requests',
    BOOKING: '/booking',

    // WebSocket
    WEBSOCKET: '/socket.io',
  },

  // Headers
  HEADERS: {
    DEFAULT: {
      'Content-Type': 'application/json',
    },
    MULTIPART: {
      'Content-Type': 'multipart/form-data',
    },
  },
} as const;

// Utility functions for building full URLs
export const buildApiUrl = (endpoint: string): string => {
  return `${API_CONFIG.BASE_URL}${endpoint}`;
};

export const buildWebSocketUrl = (path = ''): string => {
  return `${API_CONFIG.WS_BASE_URL}${path}`;
};

// Environment information
export const APP_ENV = {
  isDevelopment: import.meta.env.DEV,
  isProduction: import.meta.env.PROD,
  mode: import.meta.env.MODE,
} as const;
